import { init as initSatoriWasm } from 'satori';
import yoga from "yoga-wasm-web";
import { initWasm as initResvgWasm } from '@resvg/resvg-wasm';

const resvgWasm = import('./resvg.wasm?asset').then(mod => mod.default);
const yogaWasm = import('./yoga.wasm?asset').then(mod => mod.default);
const font400File = import('./inter-400.woff?asset').then(mod => mod.default);
const font400iFile = import('./inter-400i.woff?asset').then(mod => mod.default);
const font700File = import('./inter-700.woff?asset').then(mod => mod.default);
const font700iFile = import('./inter-700i.woff?asset').then(mod => mod.default);

const noop = () => {}
const initResvg = resvgWasm.then(buf => initResvgWasm(new WebAssembly.Module(buf))).catch(noop);
const initSatori = yogaWasm.then(buf => yoga(buf).then((x) => initSatoriWasm(x))).catch(noop);
const initFont = Promise.all([font400File, font400iFile, font700File, font700iFile]).then(([$400, $400i, $700, $700i]) => [{ name: "sans-serif", data: $400, weight: 401, style: "normal" }, { name: "sans-serif", data: $400i, weight: 401, style: "italic" }, { name: "sans-serif", data: $700, weight: 701, style: "normal" }, { name: "sans-serif", data: $700i, weight: 701, style: "italic" }]).catch(noop)

export default async function init() {
    const [fonts] = await Promise.all([initFont, initResvg, initSatori]);
    return { fonts }
}
